const lockProblemForUpdate = `-- name: LockProblemForUpdate :one
SELECT
    p.id, p.owner_user_id, p.title, p.slug, p.difficulty, p.visibility, p.status, p.time_limit_ms, p.memory_limit_kb, p.created_at, p.updated_at, p.published_at,
    coalesce(ps.id, 0)::bigint AS current_statement_id,
    coalesce(ts.id, 0)::bigint AS current_testcase_set_id,
    coalesce(ts.status, '')::text AS current_testcase_status
FROM problems p
LEFT JOIN problem_statements ps ON ps.problem_id = p.id AND ps.is_current = true
LEFT JOIN testcase_sets ts ON ts.problem_id = p.id AND ts.is_current = true
WHERE p.id = $1
FOR UPDATE OF p
`

type LockProblemForUpdateRow struct {
	ID                    int64              `db:"id" json:"id"`
	OwnerUserID           int64              `db:"owner_user_id" json:"owner_user_id"`
	Title                 string             `db:"title" json:"title"`
	Slug                  string             `db:"slug" json:"slug"`
	Difficulty            string             `db:"difficulty" json:"difficulty"`
	Visibility            string             `db:"visibility" json:"visibility"`
	Status                string             `db:"status" json:"status"`
	TimeLimitMs           int32              `db:"time_limit_ms" json:"time_limit_ms"`
	MemoryLimitKb         int32              `db:"memory_limit_kb" json:"memory_limit_kb"`
	CreatedAt             pgtype.Timestamptz `db:"created_at" json:"created_at"`
	UpdatedAt             pgtype.Timestamptz `db:"updated_at" json:"updated_at"`
	PublishedAt           pgtype.Timestamptz `db:"published_at" json:"published_at"`
	CurrentStatementID    int64              `db:"current_statement_id" json:"current_statement_id"`
	CurrentTestcaseSetID  int64              `db:"current_testcase_set_id" json:"current_testcase_set_id"`
	CurrentTestcaseStatus string             `db:"current_testcase_status" json:"current_testcase_status"`
}

func (q *Queries) LockProblemForUpdate(ctx context.Context, id int64) (LockProblemForUpdateRow, error) {
	row := q.db.QueryRow(ctx, lockProblemForUpdate, id)
	var i LockProblemForUpdateRow
	err := row.Scan(
		&i.ID,
		&i.OwnerUserID,
		&i.Title,
		&i.Slug,
		&i.Difficulty,
		&i.Visibility,
		&i.Status,
		&i.TimeLimitMs,
		&i.MemoryLimitKb,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.PublishedAt,
		&i.CurrentStatementID,
		&i.CurrentTestcaseSetID,
		&i.CurrentTestcaseStatus,
	)
	return i, err
}

const nextProblemStatementVersion = `-- name: NextProblemStatementVersion :one
SELECT coalesce(max(version), 0)::integer + 1 AS next_version
FROM problem_statements
WHERE problem_id = $1
`

func (q *Queries) NextProblemStatementVersion(ctx context.Context, problemID int64) (int32, error) {
	row := q.db.QueryRow(ctx, nextProblemStatementVersion, problemID)
	var next_version int32
	err := row.Scan(&next_version)
	return next_version, err
}

const nextTestcaseSetVersion = `-- name: NextTestcaseSetVersion :one
SELECT coalesce(max(version), 0)::integer + 1 AS next_version
FROM testcase_sets
WHERE problem_id = $1
`

func (q *Queries) NextTestcaseSetVersion(ctx context.Context, problemID int64) (int32, error) {
	row := q.db.QueryRow(ctx, nextTestcaseSetVersion, problemID)
	var next_version int32
	err := row.Scan(&next_version)
	return next_version, err
}

const updateProblem = `-- name: UpdateProblem :one
UPDATE problems
SET title = coalesce($1, title),
    slug = coalesce($2, slug),
    difficulty = coalesce($3, difficulty),
    visibility = coalesce($4, visibility),
    status = coalesce($5, status),
    time_limit_ms = coalesce($6, time_limit_ms),
    memory_limit_kb = coalesce($7, memory_limit_kb),
    published_at = CASE
        WHEN $5::text = 'published' AND published_at IS NULL THEN now()
        WHEN $5::text IS NULL THEN published_at
        ELSE published_at
    END,
    updated_at = now()
WHERE id = $8
RETURNING id, owner_user_id, title, slug, difficulty, visibility, status, time_limit_ms, memory_limit_kb, created_at, updated_at, published_at
`

type UpdateProblemParams struct {
	Title         pgtype.Text `db:"title" json:"title"`
	Slug          pgtype.Text `db:"slug" json:"slug"`
	Difficulty    pgtype.Text `db:"difficulty" json:"difficulty"`
	Visibility    pgtype.Text `db:"visibility" json:"visibility"`
	Status        pgtype.Text `db:"status" json:"status"`
	TimeLimitMs   pgtype.Int4 `db:"time_limit_ms" json:"time_limit_ms"`
	MemoryLimitKb pgtype.Int4 `db:"memory_limit_kb" json:"memory_limit_kb"`
	ID            int64       `db:"id" json:"id"`
}

func (q *Queries) UpdateProblem(ctx context.Context, arg UpdateProblemParams) (Problem, error) {
	row := q.db.QueryRow(ctx, updateProblem,
		arg.Title,
		arg.Slug,
		arg.Difficulty,
		arg.Visibility,
		arg.Status,
		arg.TimeLimitMs,
		arg.MemoryLimitKb,
		arg.ID,
	)
	var i Problem
	err := row.Scan(
		&i.ID,
		&i.OwnerUserID,
		&i.Title,
		&i.Slug,
		&i.Difficulty,
		&i.Visibility,
		&i.Status,
		&i.TimeLimitMs,
		&i.MemoryLimitKb,
		&i.CreatedAt,
		&i.UpdatedAt,
		&i.PublishedAt,
	)
	return i, err
}
